const body = msg.payload || {};
const data = body.data || {};
const key = data.key || {};
const event = String(body.event || '').toLowerCase();

function onlyDigits(v) { return String(v || '').replace(/\D/g, ''); }
function isGroupOrStatus(jid) {
  jid = String(jid || '');
  return jid.endsWith('@g.us') || jid === 'status@broadcast' || jid.includes('@newsletter');
}
function isRealWhatsappJid(jid) {
  jid = String(jid || '');
  return jid.endsWith('@s.whatsapp.net') || jid.endsWith('@c.us');
}
function looksLikeLid(jid) { return String(jid || '').includes('@lid'); }

if (event !== 'messages.upsert') {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'evento_ignorado', event: body.event || null };
  return [null, msg, null];
}

if (key.fromMe === true) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'fromMe' };
  return [null, msg, null];
}

const candidates = [
  key.remoteJidAlt,
  body.senderPn,
  data.senderPn,
  body.sender,
  data.sender,
  key.participant,
  data.participant,
  key.remoteJid
].filter(Boolean);

let chosen = candidates.find(j => isRealWhatsappJid(j) && !isGroupOrStatus(j));
if (!chosen) chosen = candidates.find(j => !looksLikeLid(j) && !isGroupOrStatus(j));
if (!chosen) chosen = candidates[0] || '';

const instance = body.instance || body.instanceName || data.instance || data.instanceName || 'danielteste';
const pushName = body.pushName || data.pushName || 'Cliente';

if (!chosen || looksLikeLid(chosen) || isGroupOrStatus(chosen)) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'lid_sem_numero_real', instance };
  return [null, msg, null];
}

const number = onlyDigits(chosen);
if (!number) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'numero_invalido', instance };
  return [null, msg, null];
}

let receivedText = '';
if (data.message) {
  receivedText = data.message.conversation
    || data.message.extendedTextMessage?.text
    || data.message.imageMessage?.caption
    || data.message.videoMessage?.caption
    || data.message.documentMessage?.caption
    || '';
}
receivedText = String(receivedText || '').trim();
if (!receivedText) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'mensagem_sem_texto', instance, number };
  return [null, msg, null];
}

const dedupeWindowMs = 15000;
const now = Date.now();
const dedupeStore = flow.get('dedupeStore') || {};
const messageId = key.id || data.id || body.id || '';
const dedupeKey = messageId
  ? `${instance}:${number}:msgid:${messageId}`
  : `${instance}:${number}:text:${receivedText.toLowerCase()}`;

for (const k in dedupeStore) {
  if (now - dedupeStore[k] > dedupeWindowMs) delete dedupeStore[k];
}
if (dedupeStore[dedupeKey] && (now - dedupeStore[dedupeKey] < dedupeWindowMs)) {
  flow.set('dedupeStore', dedupeStore);
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'mensagem_duplicada', instance, number };
  return [null, msg, null];
}
dedupeStore[dedupeKey] = now;
flow.set('dedupeStore', dedupeStore);

const floodWindowMs = 5000;
const floodStore = flow.get('floodStore') || {};
const floodKey = `${instance}:${number}`;
if (floodStore[floodKey] && (now - floodStore[floodKey] < floodWindowMs)) {
  msg.statusCode = 200;
  msg.payload = { ok: true, ignored: true, reason: 'flood_bloqueado', instance, number };
  return [null, msg, null];
}
floodStore[floodKey] = now;
flow.set('floodStore', floodStore);

const memoryKey = `memory:${instance}:${number}`;
let history = flow.get(memoryKey) || [];
history = Array.isArray(history) ? history.slice(-10) : [];

msg._meta = {
  event, instance, pushName, number, receivedText, dedupeKey, memoryKey
};
msg._history = history;
return [msg, null, msg];

const history = msg._history || [];
const messages = [
  {
    role: 'system',
    content: 'Você é um atendente profissional no WhatsApp. Responda em português do Brasil, seja claro, educado e objetivo, não invente informações, se faltar contexto peça mais detalhes, não diga que é IA a menos que perguntem e mantenha respostas curtas ou médias.'
  }
];
for (const item of history) {
  if (item && item.role && item.content) messages.push({ role: item.role, content: item.content });
}
messages.push({
  role: 'user',
  content: `Nome do cliente: ${msg._meta.pushName}\nNúmero: ${msg._meta.number}\n\nMensagem atual do cliente:\n${msg._meta.receivedText}`
});

msg.method = 'POST';
msg.url = 'https://api.mistral.ai/v1/chat/completions';
msg.headers = {
  'Authorization': 'Bearer ' + env.get('MISTRAL_API_KEY'),
  'Content-Type': 'application/json'
};
msg.payload = {
  model: 'mistral-small-latest',
  messages,
  max_tokens: 300,
  temperature: 0.3
};
return msg;

let aiText = '';
if (typeof msg.payload === 'string') aiText = msg.payload;
else if (msg.payload?.choices?.[0]?.message?.content) aiText = msg.payload.choices[0].message.content;
else if (msg.payload?.message) aiText = msg.payload.message;
else if (msg.payload?.content) aiText = msg.payload.content;
else if (msg.payload?.text) aiText = msg.payload.text;

if (Array.isArray(aiText)) {
  aiText = aiText.map(part => typeof part === 'string' ? part : (part?.text || '')).join(' ');
}
aiText = String(aiText || '').trim();
if (!aiText) aiText = 'Recebi sua mensagem. Em breve retorno com mais detalhes.';

const memoryKey = msg._meta.memoryKey;
let history = flow.get(memoryKey) || [];
history = Array.isArray(history) ? history : [];
history.push({ role: 'user', content: msg._meta.receivedText, ts: Date.now() });
history.push({ role: 'assistant', content: aiText, ts: Date.now() });
history = history.slice(-10);
flow.set(memoryKey, history);

msg.method = 'POST';
msg.url = `http://evolution-api:8080/message/sendText/${encodeURIComponent(msg._meta.instance)}`;
msg.headers = {
  'Content-Type': 'application/json',
  'apikey': env.get('EVOLUTION_API_KEY')
};
msg.payload = {
  number: msg._meta.number,
  text: aiText,
  delay: 1000,
  linkPreview: false
};
msg._debug_ai = { number: msg._meta.number, pergunta: msg._meta.receivedText, resposta: aiText };
return msg;

const memoryKey = msg._meta?.memoryKey;
if (memoryKey) {
  let history = flow.get(memoryKey) || [];
  history = Array.isArray(history) ? history : [];
  history.push({ role: 'user', content: msg._meta?.receivedText || '', ts: Date.now() });
  history.push({ role: 'assistant', content: 'Recebi sua mensagem 👍 Estou finalizando um atendimento aqui e já te respondo melhor.', ts: Date.now() });
  history = history.slice(-10);
  flow.set(memoryKey, history);
}
msg.method = 'POST';
msg.url = `http://evolution-api:8080/message/sendText/${encodeURIComponent(msg._meta?.instance || 'danielteste')}`;
msg.headers = {
  'Content-Type': 'application/json',
  'apikey': env.get('EVOLUTION_API_KEY')
};
msg.payload = {
  number: msg._meta?.number,
  text: 'Recebi sua mensagem 👍\n\nEstou finalizando um atendimento aqui e já te respondo melhor.',
  delay: 1000,
  linkPreview: false
};
return msg;
